package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

const decomposerPromptSource = "bead-lifecycle-decompose"
const preClaimDecomposerPromptSource = "bead-lifecycle-preclaim-decompose"
const decomposerDefaultTimeout = 8 * time.Minute

// DecomposeResult is the outcome of a runDecomposer invocation.
type DecomposeResult struct {
	Failed   bool
	Reason   string
	ChildIDs []string
	CostUSD  float64
}

type decomposerChild struct {
	Title       string   `json:"title"`
	Description string   `json:"description"`
	Acceptance  string   `json:"acceptance"`
	Labels      []string `json:"labels,omitempty"`
}

type decomposerEventBody struct {
	ChildIDs []string `json:"child_ids"`
	CostUSD  float64  `json:"cost_usd,omitempty"`
}

// NewPreClaimDecompositionHook dispatches an orchestrator splitter for beads
// that readiness classifies as too_large without returning concrete children.
// It returns a lossless split proposal; the execute loop owns validation,
// child creation, dependency wiring, and fallback behavior.
func NewPreClaimDecompositionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) func(context.Context, string) (*PreClaimDecomposition, error) {
	return func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
		return runPreClaimDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
	}
}

func runPreClaimDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) (*PreClaimDecomposition, error) {
	tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
	defer cancel()

	b, err := store.Get(ctx, beadID)
	if err != nil {
		return nil, fmt.Errorf("decomposer: load bead: %w", err)
	}
	prompt, err := buildPreClaimDecomposerPrompt(store, b)
	if err != nil {
		return nil, err
	}
	runtime := AgentRunRuntime{
		Prompt:           prompt,
		PromptSource:     preClaimDecomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}
	result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil {
		if tctx.Err() != nil {
			return nil, tctx.Err()
		}
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, fmt.Sprintf("dispatch error: %s", err.Error())); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: dispatch: %w", err)
	}
	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "empty output"); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: empty output")
	}
	decomp, ok := parsePreClaimDecompositionOutput(output)
	if !ok {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, "invalid output"); fallbackErr == nil {
			return fallback, nil
		}
		return nil, fmt.Errorf("decomposer: invalid output")
	}
	if err := validatePreClaimDecomposition(decomp); err != nil {
		if fallback, fallbackErr := fallbackPreClaimDecomposition(b, err.Error()); fallbackErr == nil {
			return fallback, nil
		}
		return nil, err
	}
	return decomp, nil
}

// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
// dispatches runDecomposer for TooLarge failure class.
func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
	return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		if failureClass != TooLarge {
			return &PostLadderExhaustionResult{Attempted: false}, nil
		}
		result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
		if result.Failed {
			return &PostLadderExhaustionResult{
				Attempted: true,
				Succeeded: false,
				Path:      Decompose,
				CostUSD:   result.CostUSD,
			}, nil
		}
		return &PostLadderExhaustionResult{
			Attempted: true,
			Succeeded: true,
			Path:      Decompose,
			CostUSD:   result.CostUSD,
		}, nil
	}
}

// runDecomposer dispatches a smart+ powerClass agent to split the bead into child
// beads after the escalation ladder has been exhausted. On success, child beads
// are created with Parent=beadID, the parent's execution-eligible is set to
// false, and a "decompose-applied" event is emitted. On failure a
// DecomposeResult with Failed=true is returned.
func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
	tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
	defer cancel()

	b, err := store.Get(ctx, beadID)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "store_error"}
	}

	prompt, err := buildDecomposerPrompt(store, b)
	if err != nil {
		return DecomposeResult{Failed: true, Reason: "prompt_error"}
	}

	runtime := AgentRunRuntime{
		Prompt:           prompt,
		PromptSource:     decomposerPromptSource,
		ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
		ClearRoutingPins: true,
		ClearProfile:     true,
		ClearMinPower:    true,
		ClearMaxPower:    true,
	}

	result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
	if err != nil && result == nil {
		if tctx.Err() != nil {
			return DecomposeResult{Failed: true, Reason: "timeout"}
		}
		return DecomposeResult{Failed: true, Reason: "dispatch_error"}
	}

	output := strings.TrimSpace(result.CondensedOutput)
	if output == "" {
		output = strings.TrimSpace(result.Output)
	}
	if output == "" {
		return DecomposeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
	}

	children, ok := parseDecomposerOutput(output)
	if !ok {
		return DecomposeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
	}

	if len(children) < 1 || len(children) > 5 {
		return DecomposeResult{Failed: true, Reason: "invalid_count", CostUSD: result.CostUSD}
	}

	for _, child := range children {
		if strings.TrimSpace(child.Title) == "" ||
			strings.TrimSpace(child.Description) == "" ||
			strings.TrimSpace(child.Acceptance) == "" {
			return DecomposeResult{Failed: true, Reason: "malformed_child", CostUSD: result.CostUSD}
		}
	}

	childIDs := make([]string, 0, len(children))
	for _, child := range children {
		nb := &bead.Bead{
			Title:       strings.TrimSpace(child.Title),
			Description: strings.TrimSpace(child.Description),
			Acceptance:  strings.TrimSpace(child.Acceptance),
			Labels:      append([]string(nil), child.Labels...),
			Parent:      beadID,
		}
		if err := store.Create(context.Background(), nb); err != nil {
			return DecomposeResult{Failed: true, Reason: "create_error"}
		}
		childIDs = append(childIDs, nb.ID)
	}

	_ = store.Update(context.Background(), beadID, func(b *bead.Bead) {
		ensureBeadExtra(b)
		b.Extra[bead.ExtraExecutionElig] = false
	})

	body, _ := json.Marshal(decomposerEventBody{
		ChildIDs: childIDs,
		CostUSD:  result.CostUSD,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "decompose-applied",
		Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
		Body:      string(body),
		Actor:     "ddx work",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC(),
	})

	return DecomposeResult{
		Failed:   false,
		ChildIDs: childIDs,
		CostUSD:  result.CostUSD,
	}
}

func buildDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
	type failureEntry struct {
		Summary string `json:"summary"`
		Body    string `json:"body,omitempty"`
	}
	type envelope struct {
		Title          string         `json:"title"`
		Description    string         `json:"description"`
		Acceptance     string         `json:"acceptance"`

package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	doctorFindingKindOversizedField       = "oversized_field"
	doctorFindingKindParentAncestorInDeps = "parent_ancestor_in_deps"
	doctorFindingKindUnparseableLine      = "unparseable_line"
)

// DoctorFinding reports a single bead doctor issue. Findings cover oversized
// field values, dependency edges that point back into the bead's parent chain,
// and line-level parse failures.
type DoctorFinding struct {
	Kind         string   `json:"kind,omitempty"`
	BeadID       string   `json:"bead_id"`
	FieldPath    string   `json:"field_path"`
	TargetID     string   `json:"target_id,omitempty"`
	DependencyID string   `json:"dependency_id,omitempty"`
	AncestorID   string   `json:"ancestor_id,omitempty"`
	ParentChain  []string `json:"parent_chain,omitempty"`
	SizeBytes    int      `json:"size_bytes,omitempty"`
	SampleHead   string   `json:"sample_head,omitempty"`
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings.
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

type doctorRow struct {
	lineNo   int
	rawLine  []byte
	raw      map[string]any
	bead     *Bead
	parseErr error
}

func loadDoctorRows(path string) ([]doctorRow, error) {
	src, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	lines := bytes.Split(src, []byte{'\n'})
	rows := make([]doctorRow, 0, len(lines))
	for i, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			continue
		}
		row := doctorRow{
			lineNo:  i + 1,
			rawLine: append([]byte(nil), line...),
		}
		if err := json.Unmarshal(trimmed, &row.raw); err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		bead, err := unmarshalBead(trimmed)
		if err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		row.bead = &bead
		rows = append(rows, row)
	}
	return rows, nil
}

// BeadDoctor scans a beads.jsonl file and returns every oversized field and
// every dependency edge that points back into the bead's parent chain.
// Lines that fail to parse are reported as a single finding with
// Kind=unparseable_line and the raw line as the sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	rows, err := loadDoctorRows(path)
	if err != nil {
		return report, err
	}

	byID := make(map[string]*Bead, len(rows))
	for _, row := range rows {
		if row.bead == nil || row.bead.ID == "" {
			continue
		}
		byID[row.bead.ID] = row.bead
	}

	for _, row := range rows {
		if row.parseErr != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       doctorFindingKindUnparseableLine,
				BeadID:     fmt.Sprintf("line %d (unparseable)", row.lineNo),
				FieldPath:  "line",
				SizeBytes:  len(bytes.TrimSpace(row.rawLine)),
				SampleHead: firstN(string(bytes.TrimSpace(row.rawLine)), 80),
			})
			continue
		}
		if row.bead == nil {
			continue
		}
		report.Findings = append(report.Findings, oversizedFieldFindings(row.bead)...)
		report.Findings = append(report.Findings, parentAncestorDepFindings(row.bead, byID)...)
	}

	sortDoctorFindings(report.Findings)
	return report, nil
}

func oversizedFieldFindings(b *Bead) []DoctorFinding {
	findings := make([]DoctorFinding, 0, 5)
	if b == nil {
		return findings
	}
	for _, field := range []string{"description", "acceptance", "notes"} {
		if s := beadFieldString(b, field); len(s) > MaxFieldBytes {
			findings = append(findings, DoctorFinding{
				Kind:       doctorFindingKindOversizedField,
				BeadID:     b.ID,
				FieldPath:  field,
				SizeBytes:  len(s),
				SampleHead: firstN(s, 80),
			})
		}
	}
	for i, ev := range decodeBeadEvents(b.Extra["events"]) {
		for _, field := range []string{"body", "summary"} {
			if s := beadEventString(ev, field); len(s) > MaxFieldBytes {
				findings = append(findings, DoctorFinding{
					Kind:       doctorFindingKindOversizedField,
					BeadID:     b.ID,
					FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
	}
	return findings
}

func beadFieldString(b *Bead, field string) string {
	switch field {
	case "description":
		return b.Description
	case "acceptance":
		return b.Acceptance
	case "notes":
		return b.Notes
	default:
		return ""
	}
}

func beadEventString(ev BeadEvent, field string) string {
	switch field {
	case "body":
		return ev.Body
	case "summary":
		return ev.Summary
	default:
		return ""
	}
}

func parentAncestorDepFindings(b *Bead, byID map[string]*Bead) []DoctorFinding {
	if b == nil {
		return nil
	}
	chain, _ := beadParentChain(byID, b.Parent)
	if len(chain) == 0 || len(b.Dependencies) == 0 {
		return nil
	}
	ancestorSet := make(map[string]struct{}, len(chain))
	for _, ancestorID := range chain {
		ancestorSet[ancestorID] = struct{}{}
	}

	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		if _, ok := ancestorSet[dep.DependsOnID]; !ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindParentAncestorInDeps,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     dep.DependsOnID,
			DependencyID: dep.DependsOnID,
			AncestorID:   dep.DependsOnID,
			ParentChain:  append([]string(nil), chain...),
			SampleHead:   strings.Join(chain, " -> "),
		})
	}
	return findings
}

func sortDoctorFindings(findings []DoctorFinding) {
	sort.SliceStable(findings, func(i, j int) bool {
		if findings[i].BeadID != findings[j].BeadID {
			return findings[i].BeadID < findings[j].BeadID
		}
		if doctorFindingKindRank(findings[i].Kind) != doctorFindingKindRank(findings[j].Kind) {
			return doctorFindingKindRank(findings[i].Kind) < doctorFindingKindRank(findings[j].Kind)
		}
		if findings[i].AncestorID != findings[j].AncestorID {
			return findings[i].AncestorID < findings[j].AncestorID
		}
		if findings[i].DependencyID != findings[j].DependencyID {
			return findings[i].DependencyID < findings[j].DependencyID
		}
		if findings[i].FieldPath != findings[j].FieldPath {
			return findings[i].FieldPath < findings[j].FieldPath
		}
		if findings[i].TargetID != findings[j].TargetID {
			return findings[i].TargetID < findings[j].TargetID
		}
		return findings[i].SampleHead < findings[j].SampleHead
	})
}

func doctorFindingKindRank(kind string) int {
	switch kind {
	case doctorFindingKindOversizedField:
		return 0
	case doctorFindingKindParentAncestorInDeps:
		return 1
	case doctorFindingKindUnparseableLine:
		return 2
	default:
		return 9
	}
}

// BeadDoctorFix rewrites oversized fields on disk and removes dependency edges
// that point back into the bead's parent chain.
//
//  1. If the file is already clean, returns the empty report without
//     touching anything.
//  2. Otherwise writes a timestamped backup under .ddx/backups/ before any
//     mutation; errors if the backup write fails.
//  3. Truncates oversized fields via capFieldBytes (head+tail+marker), then
//     writes full overflow content to

package cmd

import (
	"encoding/json"
	"fmt"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/spf13/cobra"
)

// newBeadDoctorCommand wires `ddx bead doctor` / `ddx bead doctor --fix`.
//
// Scan mode (no flags): exits non-zero if any field on any bead exceeds the
// per-field cap (ddx-f8a11202) or if a dependency points back into the bead's
// parent chain. Safe to run on any tree — no mutations.
//
// Fix mode (--fix): rewrites oversized fields in place and removes dependency
// edges that point back into the bead's parent chain. Before touching the
// tracker the command writes a timestamped backup under .ddx/backups/ so
// the original file is always recoverable. Overflow content persists as
// artifacts under .ddx/executions/<bead-id>/repair-<timestamp>/ and a
// repair event is appended to each rewritten bead. Idempotent — the second
// invocation exits 0 without writing because the scan is clean.
//
// Dangling-success mode (--dangling): detects in_progress beads whose last
// execution produced task_succeeded but CloseWithEvidence never ran. Safe
// to run on any tree — no mutations unless --fix is also passed.
// (ddx-2b2d114e)
func (f *CommandFactory) newBeadDoctorCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Detect (and optionally repair) beads.jsonl rows with oversized fields or back-edge deps",
		Long: `Scan the bead tracker for fields that exceed the per-field size cap.

Bead fields (description, acceptance, notes, events[].body, events[].summary)
are capped at 65,535 bytes so DDx-authored beads round-trip cleanly through
bd import (upstream's Dolt TEXT column limit). Fields over the cap usually
come from a writer bug that landed before the cap was enforced — for
example a reviewer stream dumped verbatim into an event body.

The doctor also scans for dependency edges whose targets appear in the bead's
parent chain. Those findings are reported as parent_ancestor_in_deps and
--fix removes only the offending edges, leaving the rest of the dependency
list untouched.

Without --fix this command only reports offending rows and exits non-zero.
With --fix it:

  1. Writes a timestamped backup to .ddx/backups/ before any mutation.
  2. Truncates each oversized field to the cap using head+tail+marker.
  3. Writes the full original payload for truncated fields to
     .ddx/executions/<bead>/repair-<timestamp>/<field>.log so forensics
     remain possible.
  4. Removes dependency edges that point back into the bead's parent chain.
  5. Appends a kind=repair event to every rewritten bead.

Idempotent: once a tracker is clean, running --fix again is a no-op.

With --dangling: scan for in_progress beads whose last execution produced
task_succeeded but whose bead-close step never ran (dangling-success).
For each finding, reports whether result_rev is reachable from HEAD:
  - reachable=true:  merge succeeded, close didn't. Safe to close manually
    with: ddx bead close <bead-id>
  - reachable=false: the merge itself was never applied (dangling commit).
    The result_rev is shown for manual git cherry-pick or re-attempt.
(ddx-2b2d114e)`,
		RunE: func(cmd *cobra.Command, args []string) error {
			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("bead doctor: no .ddx workspace found")
			}
			path := ddxroot.JoinProject(workspace, "beads.jsonl")

			doFix, _ := cmd.Flags().GetBool("fix")
			asJSON, _ := cmd.Flags().GetBool("json")
			doDangling, _ := cmd.Flags().GetBool("dangling")

			// --dangling mode: detect dangling-success beads (ddx-2b2d114e).
			if doDangling {
				findings, err := agent.DetectDanglingSuccessBeads(workspace)
				if err != nil {
					return fmt.Errorf("bead doctor --dangling: %w", err)
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(struct {
						Clean    bool                           `json:"clean"`
						Findings []agent.DanglingSuccessFinding `json:"findings"`
					}{
						Clean:    len(findings) == 0,
						Findings: findings,
					})
				}
				out := cmd.OutOrStdout()
				if len(findings) == 0 {
					fmt.Fprintf(out, "bead doctor --dangling: clean (no dangling-success beads detected)\n")
					return nil
				}
				fmt.Fprintf(out, "bead doctor --dangling: %d finding(s):\n", len(findings))
				for _, fi := range findings {
					reachableStr := "reachable=false (dangling commit — merge never applied)"
					recovery := "  recovery: git cherry-pick or re-run ddx try " + fi.BeadID
					if fi.Reachable {
						reachableStr = "reachable=true (merge succeeded, close didn't run)"
						recovery = "  recovery: ddx bead close " + fi.BeadID + "  # or re-run ddx try"
					}
					fmt.Fprintf(out, "  %s  attempt=%s  result_rev=%s\n    %s\n%s\n",
						fi.BeadID, fi.AttemptID, fi.ResultRev, reachableStr, recovery)
				}
				return fmt.Errorf("bead doctor --dangling: %d finding(s) detected", len(findings))
			}

			var report bead.DoctorReport
			var err error
			if doFix {
				report, err = bead.BeadDoctorFix(path, nil)
			} else {
				report, err = bead.BeadDoctor(path)
			}
			if err != nil {
				return err
			}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					Path     string               `json:"path"`
					Fixed    bool                 `json:"fixed"`
					Clean    bool                 `json:"clean"`
					Findings []bead.DoctorFinding `json:"findings"`
				}{
					Path:     report.Path,
					Fixed:    doFix && !report.Clean(),
					Clean:    report.Clean(),
					Findings: report.Findings,
				})
			}

			out := cmd.OutOrStdout()
			if report.Clean() {
				fmt.Fprintf(out, "bead doctor: %s — clean (no oversized fields or parent-ancestor deps detected)\n", path)
				return nil
			}
			fmt.Fprintf(out, "bead doctor: %s — %d finding(s):\n", path, len(report.Findings))
			for _, f := range report.Findings {
				fmt.Fprintln(out, formatBeadDoctorFinding(f))
			}
			if doFix {
				fmt.Fprintf(out, "\nrepair complete. backup written to %s/backups/.\n", filepath.Dir(path))
				if hasBeadDoctorKind(report.Findings, "oversized_field") {
					fmt.Fprintf(out, "truncated fields were captured under %s/executions/<bead>/repair-*/\n", filepath.Dir(path))
				}
				return nil
			}
			// Non-fix scan: non-zero exit via cobra error so CI can catch it.
			return fmt.Errorf("bead doctor: %d finding(s) — run `ddx bead doctor --fix` to repair", len(report.Findings))
		},
	}
	cmd.Flags().Bool("fix", false, "Rewrite oversized fields in place after writing a backup")
	cmd.Flags().Bool("json", false, "Output findings as JSON")
	cmd.Flags().Bool("dangling", false, "Detect in_progress beads with a prior task_succeeded result (dangling-success, ddx-2b2d114e)")
	return cmd
}

func formatBeadDoctorFinding(f bead.DoctorFinding) string {
	switch f.Kind {
	case "parent_ancestor_in_deps":
		chain := f.SampleHead
		if len(f.ParentChain) > 0 {
			chain = strings.Join(f.ParentChain, " -> ")
		}
		return fmt.Sprintf("  %s  %s  %s  dependency=%s  ancestor=%s  chain=%s", f.BeadID, f.Kind, f.FieldPath, f.DependencyID, f.AncestorID, chain)
	case "unparseable_line":
		return fmt.Sprintf("  %s  %s  size=%d  head=%q", f.BeadID, f.Kind, f.SizeBytes, f.SampleHead)
	default:
		return fmt.Sprintf("  %s  %s  %s  %d bytes  head=%q", f.BeadID, f.Kind, f.FieldPath, f.SizeBytes, f.SampleHead)
	}
}

func hasBeadDoctorKind(findings []bead.DoctorFinding, kind string) bool {
	for _, f := range findings {
		if f.Kind == kind {
			return true
		}
	}
	return false
}

