	"github.com/spf13/cobra"
)

func (f *CommandFactory) newAcCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "ac",
		Short: "Run pre-merge checks (declared in .ddx/checks/*.yaml)",
	}
	cmd.AddCommand(f.newAcRunCommand())
	return cmd
}

func (f *CommandFactory) newAcRunCommand() *cobra.Command {
	var only string
	var fromRev string
	cmd := &cobra.Command{
		Use:   "run <bead-id>",
		Short: "Run all applicable checks against the current worktree",
		Long: `Run every check in .ddx/checks/*.yaml whose applies_to filter matches the
named bead and the changed paths between DIFF_BASE and HEAD. Each check
runs in parallel and writes its result file under .ddx/executions/ac-<ts>/.

Exits 1 if any check returns block or error.`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			beadID := args[0]
			projectRoot := f.WorkingDir

			b, err := loadBead(projectRoot, beadID)
			if err != nil {
				return fmt.Errorf("load bead: %w", err)
			}

			diffHead, err := gitRevParse(projectRoot, "HEAD")
			if err != nil {
				return fmt.Errorf("resolve HEAD: %w", err)
			}
			diffBase := fromRev
			if diffBase == "" {
				diffBase = beadBaseRev(b)
			}
			if diffBase == "" {
				diffBase, _ = gitMergeBase(projectRoot, "HEAD", "main")
			}
			if diffBase == "" {
				diffBase = diffHead // empty diff fallback
			}

			changed, err := gitChangedPaths(projectRoot, diffBase, diffHead)
			if err != nil {
				return fmt.Errorf("diff paths: %w", err)
			}

			all, err := checks.LoadDir(ddxroot.JoinProject(projectRoot, "checks"))
			if err != nil {
				return err
			}
			if only != "" {
				all = filterByName(all, only)
				if len(all) == 0 {
					return fmt.Errorf("no check named %q", only)
				}
			}

			attemptID := newAttemptID()
			evidenceDir := ddxroot.JoinProject(projectRoot, "executions", "ac-"+attemptID)
			ictx := checks.InvocationContext{
				BeadID:       beadID,
				DiffBase:     diffBase,
				DiffHead:     diffHead,
				ProjectRoot:  projectRoot,
				EvidenceDir:  evidenceDir,
				AttemptID:    attemptID,
				BeadLabels:   b.Labels,
				ChangedPaths: changed,
			}

			results, err := checks.Run(cmd.Context(), all, ictx)
			if err != nil {
				return err
			}

			out := cmd.OutOrStdout()
			fmt.Fprintf(out, "ac run %s (bead=%s base=%s head=%s checks=%d evidence=%s)\n",
				attemptID, beadID, shortSHA(diffBase), shortSHA(diffHead), len(results), evidenceDir)
			anyBad := false
			for _, r := range results {
				marker := "PASS"
				switch r.Status {
				case checks.StatusBlock:
					marker = "BLOCK"
					anyBad = true
				case checks.StatusError:
					marker = "ERROR"
					anyBad = true
				}
				fmt.Fprintf(out, "  [%s] %s — %s\n", marker, r.Name, r.Message)
				for _, v := range r.Violations {
					loc := v.File
					if v.Line > 0 {
						loc = fmt.Sprintf("%s:%d", v.File, v.Line)
					}
					fmt.Fprintf(out, "      %s %s %s\n", loc, v.Symbol, v.Detail)
				}
			}
			if anyBad {
				return fmt.Errorf("one or more checks reported block/error")
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&only, "check", "", "Run only the named check")
	cmd.Flags().StringVar(&fromRev, "from", "", "Override DIFF_BASE (defaults to bead base_rev or merge-base with main)")
	return cmd
}

func loadBead(projectRoot, id string) (*bead.Bead, error) {
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	return store.Get(context.Background(), id)
}

func beadBaseRev(b *bead.Bead) string {
	if b == nil || b.Extra == nil {
		return ""
	}
	for _, k := range []string{"base_rev", "base-rev", "baseRev"} {
		if v, ok := b.Extra[k]; ok {
			if s, ok := v.(string); ok && s != "" {
				return s
			}
		}
	}
	return ""
}

func filterByName(all []checks.Check, name string) []checks.Check {
	out := make([]checks.Check, 0, 1)
	for _, c := range all {
		if c.Name == name {
			out = append(out, c)
		}
	}
	return out
}

func gitRevParse(dir, ref string) (string, error) {
	out, err := exec.Command("git", "-C", dir, "rev-parse", ref).Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func gitMergeBase(dir, a, b string) (string, error) {
	out, err := exec.Command("git", "-C", dir, "merge-base", a, b).Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func gitChangedPaths(dir, base, head string) ([]string, error) {
	if base == "" || base == head {
		return nil, nil
	}
	out, err := exec.Command("git", "-C", dir, "diff", "--name-only", base, head).Output()
	if err != nil {
		return nil, err
	}
	lines := strings.Split(strings.TrimSpace(string(out)), "\n")
	paths := make([]string, 0, len(lines))
	for _, l := range lines {
		l = strings.TrimSpace(l)
		if l != "" {
			paths = append(paths, l)
		}
	}
	return paths, nil
}

func newAttemptID() string {
	var b [4]byte
	_, _ = rand.Read(b[:])
	return time.Now().UTC().Format("20060102T150405") + "-" + hex.EncodeToString(b[:])
}

func shortSHA(s string) string {
	if len(s) >= 8 {
		return s[:8]
	}
	return s
}

// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		s.backend = NewAxonBackend(s.Dir, s.LockWait)
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init(ctx context.Context) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID(ctx context.Context) (string, error) {
	if err := ctx.Err(); err != nil {
		return "", err
	}
	prefix := s.Prefix
	if prefix == "" {
		prefix = DefaultIDPrefix
	} else if !strings.HasSuffix(prefix, "-") {
		prefix += "-"
	}
